test-code.code:
class Resource {
    fun close(res: Resource) {
        // Bad: do not call finalize() explicitly
        res.finalize()
    }
    protected fun finalize() { /* cleanup */ }
}

class Managed {
    protected fun finalize() { /* cleanup */ }
}
fun bad() {
    Managed().finalize() // violation
}

class Good {
    fun process(res: AutoCloseable) {
        res.use { /* work with res */ }
    }
}

class Resource : AutoCloseable {
    override fun close() { /* release resources */ }
}

class MyResource {
    override fun finalize() {
        super.finalize() // ok: legitimate super call within the override
    }
}

class Bad {
    private val other = Bad()
    override fun finalize() {
        super.finalize() // ok
        other.finalize() // violation: explicit call on another object
    }
}
